const toStr = (v) => String(v ?? '').trim();
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase();

const raw = $json || {};
const message = toStr(raw.chatInput || raw.message || raw.text || raw.input || '');
if (!message) throw new Error('[Normalize Chat Input] mensagem vazia.');

const lower = norm(message);
const sessionId = toStr(raw.sessionId || raw.session_id || raw.chatSessionId || raw.metadata?.sessionId || 'default');

let store;
try {
  store = this.getWorkflowStaticData('global');
} catch (_e) {
  store = {};
}
if (!store.impactDrafts) store.impactDrafts = {};

const hasDraft = !!store.impactDrafts[sessionId];
const startImpact = lower.startsWith('/impact') || lower === 'impact' || lower.startsWith('impact:') || lower.startsWith('impact ');
const cancelImpact = lower === '/cancelar' || lower === 'cancelar' || lower === '/cancel';

if (cancelImpact) {
  delete store.impactDrafts[sessionId];
  return [{ json: { route: 'impact_collect_question', output: 'Coleta de Impact Analysis cancelada. Para reiniciar, envie /impact.' } }];
}

const parseLabeled = (text, labels) => {
  for (const label of labels) {
    const re = new RegExp(label + '\\s*[:=]\\s*([^|\\n]+)', 'i');
    const m = text.match(re);
    if (m) return toStr(m[1]);
  }
  return '';
};

const ensureDraft = () => {
  if (!store.impactDrafts[sessionId]) {
    store.impactDrafts[sessionId] = {
      problema: '',
      mudanca: '',
      evidencias: '',
      restricoes: '',
      started_at: new Date().toISOString()
    };
  }
  return store.impactDrafts[sessionId];
};

const nextQuestion = (draft) => {
  if (!toStr(draft.problema)) return '1/4 Qual problema ou oportunidade essa alteracao resolve?';
  if (!toStr(draft.mudanca)) return '2/4 Descreva a mudanca como voce espera ver no produto.';
  if (!toStr(draft.evidencias)) return '3/4 Quais evidencias comprovam que a entrega esta pronta?';
  if (!toStr(draft.restricoes)) return '4/4 Restricoes: limites de prazo, compliance, integracoes proibidas, etc.';
  return '';
};

const summaryDraft = (draft) => [
  '- problema: ' + (toStr(draft.problema) || '(pendente)'),
  '- mudanca: ' + (toStr(draft.mudanca) || '(pendente)'),
  '- evidencias: ' + (toStr(draft.evidencias) || '(pendente)'),
  '- restricoes: ' + (toStr(draft.restricoes) || '(pendente)')
].join('\n');

if (startImpact || hasDraft) {
  const draft = ensureDraft();

  const p = parseLabeled(message, ['problema', 'problem']);
  const m = parseLabeled(message, ['mudanca', 'mudança', 'expected_change']);
  const e = parseLabeled(message, ['evidencias', 'evidências', 'evidence']);
  const r = parseLabeled(message, ['restricoes', 'restrições', 'constraints']);

  if (p) draft.problema = p;
  if (m) draft.mudanca = m;
  if (e) draft.evidencias = e;
  if (r) draft.restricoes = r;

  const notLabeled = !(p || m || e || r);
  if (notLabeled && !startImpact) {
    if (!toStr(draft.problema)) draft.problema = message;
    else if (!toStr(draft.mudanca)) draft.mudanca = message;
    else if (!toStr(draft.evidencias)) draft.evidencias = message;
    else if (!toStr(draft.restricoes)) draft.restricoes = message;
  }

  const next = nextQuestion(draft);
  if (next) {
    return [{
      json: {
        route: 'impact_collect_question',
        output: [
          'Modo Impact Analysis ativo.',
          '',
          summaryDraft(draft),
          '',
          next,
          '',
          'Dica: voce pode responder por partes ou enviar tudo rotulado: problema:, mudanca:, evidencias:, restricoes:.'
        ].join('\n')
      }
    }];
  }

  const payload = {
    problema: toStr(draft.problema),
    mudanca: toStr(draft.mudanca),
    evidencias: toStr(draft.evidencias),
    restricoes: toStr(draft.restricoes)
  };

  delete store.impactDrafts[sessionId];

  return [{
    json: {
      route: 'impact_run',
      impact_workflow_id: toStr(($env && $env.IMPACT_WORKFLOW_ID) || ''),
      impact_payload: payload,
      output: [
        'Dados coletados. Vou disparar o subflow de Impact Analysis agora.',
        '',
        summaryDraft(payload)
      ].join('\n')
    }
  }];
}

return [{
  json: {
    route: 'pr_qa',
    question: message,
    owner: toStr(($env && $env.GITHUB_OWNER) || 'oliversoft-tech'),
    github_token: toStr(($env && $env.GITHUB_TOKEN) || ''),
    llm_model: toStr(($env && $env.LLM_MODEL) || 'claude-3-5-sonnet-20241022'),
  }
}];

const wf = String($json.impact_workflow_id || '').trim();
if (!wf) throw new Error('[Prepare Impact Inputs] IMPACT_WORKFLOW_ID ausente no environment.');
return [{
  json: {
    impact_workflow_id: wf,
    problema: $json.impact_payload?.problema || '',
    mudanca: $json.impact_payload?.mudanca || '',
    evidencias: $json.impact_payload?.evidencias || '',
    restricoes: $json.impact_payload?.restricoes || ''
  }
}];

const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => { const n = Number(v); return Number.isFinite(n) ? n : null; };

const req = $json || {};
const question = toStr(req.question || '');
const owner = toStr(req.owner || 'oliversoft-tech');
const token = toStr(req.github_token || '');
if (!token) throw new Error('[Fetch PR Context] GITHUB_TOKEN ausente no environment.');

const reposFromTable = $items('Load Repos Table', 0, 0).map((i) => i.json || {});
let repos = reposFromTable
  .map((r) => toStr(r.repo_name || r.name || r.repository || r.slug || ''))
  .filter(Boolean)
  .filter((n) => n.includes('fastroute-'));
if (repos.length === 0) repos = ['fastroute-domain', 'fastroute-api', 'fastroute-mobile-hybrid', 'fastroute-changemanagement'];
repos = [...new Set(repos)];

const gh = async (url) => this.helpers.httpRequest({
  method: 'GET',
  url,
  headers: {
    Authorization: 'Bearer ' + token,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  json: true
});

const allPrs = [];
for (const repo of repos) {
  const list = await gh('https://api.github.com/repos/' + owner + '/' + repo + '/pulls?state=all&sort=updated&direction=desc&per_page=100');
  for (const pr of (Array.isArray(list) ? list : [])) {
    const title = toStr(pr.title);
    const headRef = toStr(pr.head?.ref || '');
    const governanceLike = title.toLowerCase().includes('governance: impact analysis') || headRef.startsWith('codex/governance-');
    if (!governanceLike) continue;

    allPrs.push({
      repo,
      number: pr.number,
      title,
      state: pr.state,
      draft: !!pr.draft,
      created_at: pr.created_at,
      updated_at: pr.updated_at,
      merged_at: pr.merged_at,
      user: toStr(pr.user?.login || ''),
      url: toStr(pr.html_url || ''),
      body: toStr(pr.body || '').slice(0, 5000),
      head: toStr(pr.head?.ref || ''),
      base: toStr(pr.base?.ref || '')
    });
  }
}

allPrs.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
const selected = allPrs.slice(0, 30);

for (const pr of selected) {
  try {
    const files = await gh('https://api.github.com/repos/' + owner + '/' + pr.repo + '/pulls/' + pr.number + '/files?per_page=100');
    pr.files = (Array.isArray(files) ? files : []).map((f) => ({
      filename: toStr(f.filename),
      status: toStr(f.status),
      additions: toNum(f.additions) || 0,
      deletions: toNum(f.deletions) || 0
    }));
  } catch (_e) {
    pr.files = [];
  }
}

return [{
  json: {
    question,
    pr_context: {
      owner,
      repos,
      total_found: allPrs.length,
      selected_count: selected.length,
      prs: selected
    }
  }
}];

const toStr = (v) => String(v ?? '').trim();
const text = toStr($json.text || $json.response?.text || '');
if (!text) throw new Error('[Build PR Chat Reply] LLM retornou texto vazio.');
return [{ json: { output: text } }];
